HRESULT MRFGreenProfileSet::GetSurfaceList(CATListValCATBaseUnknown_var &oSurfaceList)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGrooveSweep(_CredentialForGreenProfile, this);

	CATFmAttributeName AttrKey;
	CATFmAttributeValue FmAttrValueList;
	AttrKey = CATFmAttributeName(_MRFGreenProfileSet_SurfaceList);

	if (!!FeatFacadeOnGrooveSweep)
	{
		rc = FeatFacadeOnGrooveSweep.GetValue(AttrKey, FmAttrValueList);

		if (SUCCEEDED(rc))
		{
			int listOfEdgeSize = FmAttrValueList.Size();

			for (int i = 1; i <= listOfEdgeSize; i++)
			{
				CATFmAttributeValue FmAttrValue;
				rc = FeatFacadeOnGrooveSweep.GetValueAtIndex(AttrKey, i, FmAttrValue);

				if (SUCCEEDED(rc))
				{
					CATFmFeatureFacade FeatFacadeOnsurfFeat;
					rc = FmAttrValue.GetFeature(FeatFacadeOnsurfFeat);
					if (SUCCEEDED(rc))
					{
						CATBaseUnknown_var surfFeat = NULL_var;
						rc = FeatFacadeOnsurfFeat.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)& surfFeat);

						if (SUCCEEDED(rc))
							oSurfaceList.Append(surfFeat);
					}
				}
			}
		}
	}
	return rc;
}
HRESULT MRFGreenProfileSet::SetSurfaceList(const CATListValCATBaseUnknown_var & iSurfaceList)
{
	int sizeOfEdgeList = iSurfaceList.Size();
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGreenProfileSet(_CredentialForGreenProfile, this);

	if ((sizeOfEdgeList > 0) && (!!FeatFacadeOnGreenProfileSet))
	{
		CATFmAttributeName AttrKey;
		AttrKey = CATFmAttributeName(_MRFGreenProfileSet_SurfaceList);

		CATFmAttributeValue FmAttrValue, FmAttrValueOnCurve, FmAttrValueOnFeat;
		CATFmFeatureFacade FeatFacadeOnCurve;
		FeatFacadeOnGreenProfileSet.GetValue(AttrKey, FmAttrValueOnFeat);
		int sizeE = FmAttrValueOnFeat.Size();
		for (int i = 1; i <= sizeE; i++)
		{
			FeatFacadeOnGreenProfileSet.DetachComponent(AttrKey, i);
		}
		FeatFacadeOnGreenProfileSet.UnsetValue(AttrKey);

		for (int i = 1; i <= sizeOfEdgeList; i++)
		{
			CATBaseUnknown_var edgeFeat = iSurfaceList[i];
			// Get input Curve feature facade			
			FeatFacadeOnCurve = edgeFeat;
			FmAttrValue.SetFeature(FeatFacadeOnCurve);

			FmAttrValueOnCurve.Append(FmAttrValue);
		}
		if (FmAttrValueOnCurve.Size() > 0)
		{
			rc = FeatFacadeOnGreenProfileSet.SetValue(AttrKey, FmAttrValueOnCurve);
			if (SUCCEEDED(rc))
			{
				//UpdateFeature();
			}
		}
	}
	return rc;
}
